-- Emily Rodriguez (JHU nursing demo) — captures, shift beats, and full Reflect.
--
-- The earlier enrich migration seeded review.sections in a {title,content} shape
-- the Reflect reader silently drops (it needs prompt-keyed sections), and never
-- seeded act captures, step_beats, or teaching_reflection. As a result Practice
-- showed empty Capture Evidence, empty Shift Beats, and only the key_takeaway of
-- the four Reflect questions.
--
-- This migration, for every nursing step across the three rotations:
--   * plan.what_will_you_do + how_sub_steps (the WHAT/HOW summary)
--   * act.observations / media_uploads / media_links (Capture Evidence)
--   * review.sections (what_worked + what_didnt, prompt-keyed) + teaching_reflection
--     (key_takeaway is preserved from the prior seed via shallow merge)
--   * step_beats rows (the shift/procedure timeline)
--
-- Future-dated Critical Care steps (CVICU handoff, Code blue sim, Sedation) are
-- planned work that has not happened yet, so they get plan + planned beats only —
-- no captures/reflection. Idempotent: fixed patches + ON CONFLICT upserts.
--
-- Emily user_id: 37ac7510-8a05-4f15-86ea-1d8714b6507d

-- ---------------------------------------------------------------------------
-- Section 1 — Med-Surg Rotation (April): plan + act + review patches
-- ---------------------------------------------------------------------------
UPDATE timeline_steps ts SET metadata =
  ts.metadata
  || jsonb_build_object('plan',   COALESCE(ts.metadata->'plan',   '{}'::jsonb) || v.plan_patch)
  || jsonb_build_object('act',    COALESCE(ts.metadata->'act',    '{}'::jsonb) || v.act_patch)
  || jsonb_build_object('review', COALESCE(ts.metadata->'review', '{}'::jsonb) || v.review_patch)
FROM (VALUES
  ('5513eb3f-5cf0-4b85-a064-4f2db5e019fe',
   '{"what_will_you_do":"Take a full set of vital signs on three assigned Med-Surg patients and hit WHO five-moments hand hygiene at every bedside.","how_sub_steps":[{"id":"aaaa0001-0000-4000-8000-000000000001","text":"Zero the vitals cart and match each BP cuff to arm circumference","sort_order":0,"completed":true},{"id":"aaaa0001-0000-4000-8000-000000000002","text":"Cross-check one automated BP with a manual reading","sort_order":1,"completed":true},{"id":"aaaa0001-0000-4000-8000-000000000003","text":"Foam in and out of every room and after glove removal","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0001-0000-4000-8000-000000000001","text":"Manual cuff read 138/86 while the monitor showed 152/90 — the cuff was a size too small. Swapped to a large adult cuff and the gap closed.","timestamp":"2026-04-03T07:40:00Z","source":"note"},{"id":"bbbb0001-0000-4000-8000-000000000002","text":"Caught myself reaching for the chart before foaming out. Reset and did the sequence in order.","timestamp":"2026-04-03T11:20:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0001-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-01a/640/480","type":"photo","caption":"Vitals cart restocked and zeroed at the start of shift.","created_at":"2026-04-03T07:50:00Z"},{"id":"cccc0001-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-01v/640/480","type":"video","caption":"Two-finger cuff-fit check before a manual blood pressure.","created_at":"2026-04-03T08:30:00Z"}],"media_links":[{"id":"dddd0001-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/hand-hygiene-five-moments.pdf","caption":"WHO Five Moments hand-hygiene pocket card (unit copy).","platform":"other","added_at":"2026-04-03T12:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Cross-checking the automated BP by hand caught a cuff-size error before it ever reached the chart.","source":"in_app","captured_at":"2026-04-03T18:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"My hand-hygiene sequence slipped when I rushed — I broke contact to grab the chart before foaming out.","source":"in_app","captured_at":"2026-04-03T18:00:00Z"}],"teaching_reflection":"I would have a learner size the cuff against the arm, take one manual reading beside the monitor, and show me both numbers and explain any gap before charting.","composed_via":"in_app"}'::jsonb),

  ('1bfc1c2c-19b5-48bf-ae60-fb0dedc82130',
   '{"what_will_you_do":"Carry a two-patient assignment on 4West for a full shift — assessments, meds, I&O, and a clean SBAR handoff.","how_sub_steps":[{"id":"aaaa0002-0000-4000-8000-000000000001","text":"Pre-chart both patients and flag overnight changes","sort_order":0,"completed":true},{"id":"aaaa0002-0000-4000-8000-000000000002","text":"Cluster care to limit room entries and interruptions","sort_order":1,"completed":true},{"id":"aaaa0002-0000-4000-8000-000000000003","text":"Reconcile I&O totals before the 1900 handoff","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0002-0000-4000-8000-000000000001","text":"Bed 4 post-op was guarding the incision and underreporting pain at rest. Reframed the question around movement and got an honest 7/10.","timestamp":"2026-04-08T09:10:00Z","source":"note"},{"id":"bbbb0002-0000-4000-8000-000000000002","text":"Lost twenty minutes hunting for a working pump. Need to check the equipment room at the top of shift, not when I need it.","timestamp":"2026-04-08T14:05:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0002-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-02a/640/480","type":"photo","caption":"Brain sheet for the two-patient 4West assignment.","created_at":"2026-04-08T07:30:00Z"}],"media_links":[{"id":"dddd0002-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/4west-shift-flow.pdf","caption":"4West Med-Surg shift-flow checklist.","platform":"other","added_at":"2026-04-08T15:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Asking about pain on movement instead of at rest surfaced a real 7/10 I would have missed.","source":"in_app","captured_at":"2026-04-08T19:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I did not scout equipment early and lost twenty minutes mid-shift looking for a working pump.","source":"in_app","captured_at":"2026-04-08T19:30:00Z"}],"teaching_reflection":"I would teach a learner to walk the equipment room and pre-chart both patients before first rounds, and show me their brain sheet with overnight changes already flagged.","composed_via":"in_app"}'::jsonb),

  ('ecdc62c8-c54d-410d-bafe-c8ce73f00bba',
   '{"what_will_you_do":"Place a peripheral IV on a Med-Surg patient using ultrasound-free landmarks, first-stick.","how_sub_steps":[{"id":"aaaa0003-0000-4000-8000-000000000001","text":"Choose a forearm vein, apply the tourniquet, and let it fill","sort_order":0,"completed":true},{"id":"aaaa0003-0000-4000-8000-000000000002","text":"Anchor the vein and insert bevel-up at a shallow angle","sort_order":1,"completed":true},{"id":"aaaa0003-0000-4000-8000-000000000003","text":"Advance the catheter, flush, and secure with a clear dressing","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0003-0000-4000-8000-000000000001","text":"Felt the flashback but advanced the catheter a hair too soon and blew the vein. Second attempt on the other forearm landed clean.","timestamp":"2026-04-10T10:25:00Z","source":"note"},{"id":"bbbb0003-0000-4000-8000-000000000002","text":"Anchoring with my non-dominant thumb made the second stick much steadier.","timestamp":"2026-04-10T10:40:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0003-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-03a/640/480","type":"photo","caption":"Secured 20-gauge in the left forearm with a clear dressing.","created_at":"2026-04-10T10:45:00Z"},{"id":"cccc0003-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-03v/640/480","type":"video","caption":"Vein anchoring and bevel-up insertion angle.","created_at":"2026-04-10T10:30:00Z"}],"media_links":[{"id":"dddd0003-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/piv-insertion-steps.pdf","caption":"Peripheral IV insertion competency checklist.","platform":"other","added_at":"2026-04-10T11:15:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Anchoring the vein with my non-dominant thumb made the second stick steady and first-time successful.","source":"in_app","captured_at":"2026-04-10T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"On the first attempt I advanced the catheter before the flashback fully settled and blew the vein.","source":"in_app","captured_at":"2026-04-10T17:00:00Z"}],"teaching_reflection":"I would have a learner pause one full second after flashback before advancing, and show me a secured line with a patent flush and no infiltration.","composed_via":"in_app"}'::jsonb),

  ('d3bb9c21-ea3b-48c7-8bc8-6ddfefc19616',
   '{"what_will_you_do":"Administer the 0900 med pass for two patients, including one IV push, with full five-rights verification.","how_sub_steps":[{"id":"aaaa0004-0000-4000-8000-000000000001","text":"Pull meds and verify each against the MAR at the cart","sort_order":0,"completed":true},{"id":"aaaa0004-0000-4000-8000-000000000002","text":"Scan patient and each med at the bedside","sort_order":1,"completed":true},{"id":"aaaa0004-0000-4000-8000-000000000003","text":"Push the IV med over the labeled time and watch for reaction","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0004-0000-4000-8000-000000000001","text":"Scanner flagged a look-alike — metoprolol tartrate pulled instead of succinate. Caught it before it left the cart.","timestamp":"2026-04-12T09:05:00Z","source":"note"},{"id":"bbbb0004-0000-4000-8000-000000000002","text":"Pushed the IV med faster than the two-minute window on the first one. Slowed down and timed it on the second.","timestamp":"2026-04-12T09:20:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0004-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-04a/640/480","type":"photo","caption":"Barcode scan confirming patient and med match the MAR.","created_at":"2026-04-12T09:10:00Z"}],"media_links":[{"id":"dddd0004-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/iv-push-rates.pdf","caption":"IV push rate reference for common Med-Surg meds.","platform":"other","added_at":"2026-04-12T10:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Barcode scanning at the cart caught a metoprolol tartrate-versus-succinate look-alike before it reached the patient.","source":"in_app","captured_at":"2026-04-12T16:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"My first IV push ran faster than the labeled two-minute window — I was watching the patient, not the clock.","source":"in_app","captured_at":"2026-04-12T16:30:00Z"}],"teaching_reflection":"I would teach a learner to set a visible timer for any slow push and show me both the scan confirmation and the elapsed push time.","composed_via":"in_app"}'::jsonb),

  ('c0f337cd-e916-4c38-8270-d9f88b2c838d',
   '{"what_will_you_do":"Run every med this shift through an explicit five-rights check and verbalize each right out loud.","how_sub_steps":[{"id":"aaaa0005-0000-4000-8000-000000000001","text":"State right patient, drug, dose, route, time at the bedside","sort_order":0,"completed":true},{"id":"aaaa0005-0000-4000-8000-000000000002","text":"Independent double-check on every high-alert med","sort_order":1,"completed":true},{"id":"aaaa0005-0000-4000-8000-000000000003","text":"Document immediately, never in batch","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0005-0000-4000-8000-000000000001","text":"Verbalizing the five rights felt slow but the patient corrected me — they had held their morning dose at home, which changed the timing.","timestamp":"2026-04-15T08:55:00Z","source":"note"},{"id":"bbbb0005-0000-4000-8000-000000000002","text":"Insulin double-check with the charge nurse caught a units misread on the sliding scale.","timestamp":"2026-04-15T11:30:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0005-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-05a/640/480","type":"photo","caption":"Sliding-scale insulin order with the independent double-check signature.","created_at":"2026-04-15T11:35:00Z"}],"media_links":[{"id":"dddd0005-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/high-alert-double-check.pdf","caption":"High-alert medication independent double-check policy.","platform":"other","added_at":"2026-04-15T12:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Saying the five rights aloud invited the patient to correct me — they had held a dose at home, which changed my timing.","source":"in_app","captured_at":"2026-04-15T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I almost batched my charting to keep pace; that is exactly how a documentation error sneaks in.","source":"in_app","captured_at":"2026-04-15T17:00:00Z"}],"teaching_reflection":"I would have a learner verbalize all five rights and bring the patient into the check, then show me a high-alert med with a real independent double-check signature.","composed_via":"in_app"}'::jsonb),

  ('24e33ea9-5094-4a16-8e08-3e6e8c506984',
   '{"what_will_you_do":"Perform a focused cardiac assessment on a telemetry patient and correlate the rhythm strip with the exam.","how_sub_steps":[{"id":"aaaa0006-0000-4000-8000-000000000001","text":"Auscultate all four valve areas and note any extra sounds","sort_order":0,"completed":true},{"id":"aaaa0006-0000-4000-8000-000000000002","text":"Check peripheral pulses, cap refill, and edema","sort_order":1,"completed":true},{"id":"aaaa0006-0000-4000-8000-000000000003","text":"Read the telemetry strip and match rate to the apical pulse","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0006-0000-4000-8000-000000000001","text":"Apical-radial pulse deficit of about 12 — telemetry showed new atrial fibrillation. Flagged the provider before the patient was symptomatic.","timestamp":"2026-04-18T10:15:00Z","source":"note"},{"id":"bbbb0006-0000-4000-8000-000000000002","text":"I heard an S3 but second-guessed it. Asked the preceptor to confirm — it was real and fit the fluid picture.","timestamp":"2026-04-18T10:35:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0006-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-06a/640/480","type":"photo","caption":"Telemetry strip showing the new irregularly irregular rhythm.","created_at":"2026-04-18T10:20:00Z"},{"id":"cccc0006-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-06v/640/480","type":"video","caption":"Apical auscultation while palpating the radial pulse for a deficit.","created_at":"2026-04-18T10:25:00Z"}],"media_links":[{"id":"dddd0006-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/telemetry-rhythm-basics.pdf","caption":"Telemetry rhythm-recognition quick reference.","platform":"other","added_at":"2026-04-18T11:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Counting apical and radial pulses together exposed a deficit and caught new atrial fibrillation before symptoms.","source":"in_app","captured_at":"2026-04-18T17:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I second-guessed a real S3 instead of trusting the exam and confirming methodically.","source":"in_app","captured_at":"2026-04-18T17:30:00Z"}],"teaching_reflection":"I would teach a learner to count apical and radial simultaneously and show me the rhythm strip alongside their documented pulse deficit.","composed_via":"in_app"}'::jsonb),

  ('f33de2ae-bb7b-47db-9d45-7e95aa3e10d7',
   '{"what_will_you_do":"Give and receive an SBAR shift handoff for a three-patient assignment without notes in front of me.","how_sub_steps":[{"id":"aaaa0007-0000-4000-8000-000000000001","text":"Build an SBAR line for each patient before report","sort_order":0,"completed":true},{"id":"aaaa0007-0000-4000-8000-000000000002","text":"Lead with the recommendation, not the backstory","sort_order":1,"completed":true},{"id":"aaaa0007-0000-4000-8000-000000000003","text":"Confirm pending tasks and read back the plan","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0007-0000-4000-8000-000000000001","text":"Buried the most important item — a held anticoagulant — at the end of report. Oncoming nurse almost missed it.","timestamp":"2026-04-20T18:50:00Z","source":"note"},{"id":"bbbb0007-0000-4000-8000-000000000002","text":"Reading back the pending labs out loud caught one I had not actually ordered yet.","timestamp":"2026-04-20T19:05:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0007-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-07a/640/480","type":"photo","caption":"SBAR handoff worksheet for the three-patient assignment.","created_at":"2026-04-20T18:40:00Z"}],"media_links":[{"id":"dddd0007-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/sbar-template.pdf","caption":"SBAR handoff template (unit standard).","platform":"other","added_at":"2026-04-20T19:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"A written SBAR line per patient and a read-back of pending labs caught one order I had not actually placed.","source":"in_app","captured_at":"2026-04-20T20:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I buried a held anticoagulant at the end of report instead of leading with it as the recommendation.","source":"in_app","captured_at":"2026-04-20T20:00:00Z"}],"teaching_reflection":"I would have a learner lead every handoff with the recommendation and one safety must, and show me a read-back where the receiver restates the plan.","composed_via":"in_app"}'::jsonb),

  ('0fc14803-aad9-448e-8b42-334901bf1d3b',
   '{"what_will_you_do":"Rotate through Bayview ED intake and triage four walk-in patients by acuity.","how_sub_steps":[{"id":"aaaa0008-0000-4000-8000-000000000001","text":"Take a focused history and a quick vital set at intake","sort_order":0,"completed":true},{"id":"aaaa0008-0000-4000-8000-000000000002","text":"Assign an ESI level and justify it","sort_order":1,"completed":true},{"id":"aaaa0008-0000-4000-8000-000000000003","text":"Re-triage anyone waiting longer than expected","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0008-0000-4000-8000-000000000001","text":"The quietest patient — minimal complaints, pale and diaphoretic — was the sickest. Bumped them up two ESI levels.","timestamp":"2026-04-22T13:10:00Z","source":"note"},{"id":"bbbb0008-0000-4000-8000-000000000002","text":"Almost anchored on a loud ankle injury. The vitals on the quiet chest-pain patient pulled me back.","timestamp":"2026-04-22T13:25:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0008-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-08a/640/480","type":"photo","caption":"ESI triage decision tree posted at the intake desk.","created_at":"2026-04-22T13:15:00Z"}],"media_links":[{"id":"dddd0008-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/esi-triage-algorithm.pdf","caption":"Emergency Severity Index triage algorithm.","platform":"other","added_at":"2026-04-22T14:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Trusting the vitals over the volume of complaints — the quiet diaphoretic patient was the one in trouble.","source":"in_app","captured_at":"2026-04-22T20:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I nearly anchored on the loudest complaint in the room before the data pulled me back.","source":"in_app","captured_at":"2026-04-22T20:30:00Z"}],"teaching_reflection":"I would teach a learner that triage is pattern recognition under time pressure, and have them justify every ESI level out loud against the vitals.","composed_via":"in_app"}'::jsonb),

  ('19512262-7cd3-4289-a3ff-7a5ec24d00f1',
   '{"what_will_you_do":"Complete a focused cardiopulmonary assessment and document a clean, system-based note.","how_sub_steps":[{"id":"aaaa0009-0000-4000-8000-000000000001","text":"Inspect, palpate, percuss, auscultate front and back","sort_order":0,"completed":true},{"id":"aaaa0009-0000-4000-8000-000000000002","text":"Compare breath sounds side to side in all fields","sort_order":1,"completed":true},{"id":"aaaa0009-0000-4000-8000-000000000003","text":"Document findings by system, not by stream of consciousness","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0009-0000-4000-8000-000000000001","text":"Crackles at the right base that cleared with cough — atelectasis, not new fluid. Got the patient up and coughing.","timestamp":"2026-04-25T09:30:00Z","source":"note"},{"id":"bbbb0009-0000-4000-8000-000000000002","text":"I rushed the posterior fields the first pass and had to go back. Comparing side to side is what made the asymmetry obvious.","timestamp":"2026-04-25T09:45:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0009-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-09a/640/480","type":"photo","caption":"Auscultation landmark map for posterior lung fields.","created_at":"2026-04-25T09:35:00Z"},{"id":"cccc0009-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-09v/640/480","type":"video","caption":"Side-to-side breath-sound comparison technique.","created_at":"2026-04-25T09:40:00Z"}],"media_links":[{"id":"dddd0009-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/respiratory-assessment.pdf","caption":"Focused respiratory assessment reference.","platform":"other","added_at":"2026-04-25T10:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Comparing breath sounds side to side made the right-base asymmetry obvious and pointed to atelectasis, not fluid.","source":"in_app","captured_at":"2026-04-25T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I rushed the posterior fields on the first pass and had to repeat them to trust the exam.","source":"in_app","captured_at":"2026-04-25T17:00:00Z"}],"teaching_reflection":"I would have a learner always auscultate symmetrically and document by system, then show me a note where each finding maps to a body system.","composed_via":"in_app"}'::jsonb),

  ('4a00f484-b460-4d85-a344-cb07063f7365',
   '{"what_will_you_do":"Deliver a tight SBAR handoff to the oncoming nurse, leading with the safety priority for each patient.","how_sub_steps":[{"id":"aaaa0010-0000-4000-8000-000000000001","text":"Rank patients by who could deteriorate first","sort_order":0,"completed":true},{"id":"aaaa0010-0000-4000-8000-000000000002","text":"State one clear recommendation per patient","sort_order":1,"completed":true},{"id":"aaaa0010-0000-4000-8000-000000000003","text":"Close the loop with a read-back","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0010-0000-4000-8000-000000000001","text":"Leading with the sickest patient and the one thing to watch made the whole report shorter and clearer.","timestamp":"2026-04-28T18:55:00Z","source":"note"},{"id":"bbbb0010-0000-4000-8000-000000000002","text":"I still over-explained the stable patient. Need to trust that stable means brief.","timestamp":"2026-04-28T19:10:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0010-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-10a/640/480","type":"photo","caption":"Prioritized handoff list, sickest patient at the top.","created_at":"2026-04-28T18:45:00Z"}],"media_links":[{"id":"dddd0010-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/handoff-priority-guide.pdf","caption":"Handoff prioritization guide for Med-Surg.","platform":"other","added_at":"2026-04-28T19:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Ranking patients by who could deteriorate first made the report shorter and put attention where it mattered.","source":"in_app","captured_at":"2026-04-28T20:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I over-explained the stable patient instead of keeping stable brief.","source":"in_app","captured_at":"2026-04-28T20:00:00Z"}],"teaching_reflection":"I would teach a learner to spend their words on the sickest patient and keep stable patients to one line, and show me a handoff that opens with the priority.","composed_via":"in_app"}'::jsonb)
) AS v(id, plan_patch, act_patch, review_patch)
WHERE ts.id = v.id::uuid;

-- ---------------------------------------------------------------------------
-- Section 3 — Critical Care Rotation (June, completed steps): plan + act + review
-- ---------------------------------------------------------------------------
UPDATE timeline_steps ts SET metadata =
  ts.metadata
  || jsonb_build_object('plan',   COALESCE(ts.metadata->'plan',   '{}'::jsonb) || v.plan_patch)
  || jsonb_build_object('act',    COALESCE(ts.metadata->'act',    '{}'::jsonb) || v.act_patch)
  || jsonb_build_object('review', COALESCE(ts.metadata->'review', '{}'::jsonb) || v.review_patch)
FROM (VALUES
  ('10667c5b-6541-4fb2-8b1b-89ec5e29bd59',
   '{"what_will_you_do":"Take a MICU patient through a high-acuity admission — lines, drips, and a full systems assessment.","how_sub_steps":[{"id":"aaaa0016-0000-4000-8000-000000000001","text":"Verify drips, channels, and alarm limits at the bedside","sort_order":0,"completed":true},{"id":"aaaa0016-0000-4000-8000-000000000002","text":"Complete a head-to-toe and set a baseline","sort_order":1,"completed":true},{"id":"aaaa0016-0000-4000-8000-000000000003","text":"Anticipate the next intervention before the provider asks","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0016-0000-4000-8000-000000000001","text":"Walking the lines head to toe before report caught a secondary infusion running into a clamped channel.","timestamp":"2026-06-03T08:15:00Z","source":"note"},{"id":"bbbb0016-0000-4000-8000-000000000002","text":"The pace was overwhelming at first. Verifying one system at a time kept me from missing something.","timestamp":"2026-06-03T09:00:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0016-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-16a/640/480","type":"photo","caption":"Labeled infusion lines at the MICU bedside.","created_at":"2026-06-03T08:20:00Z"},{"id":"cccc0016-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-16v/640/480","type":"video","caption":"Tracing each line from bag to patient during line reconciliation.","created_at":"2026-06-03T08:25:00Z"}],"media_links":[{"id":"dddd0016-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/icu-admission-checklist.pdf","caption":"ICU admission and line-reconciliation checklist.","platform":"other","added_at":"2026-06-03T10:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Tracing every line from bag to patient caught a secondary infusion running into a clamped channel.","source":"in_app","captured_at":"2026-06-03T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"The volume of data overwhelmed me early until I forced a system-by-system order.","source":"in_app","captured_at":"2026-06-03T18:30:00Z"}],"teaching_reflection":"I would teach a learner to reconcile every line head to toe before report and show me a baseline assessment organized by system.","composed_via":"in_app"}'::jsonb),

  ('d3710000-0000-4000-8000-000000000001',
   '{"what_will_you_do":"Titrate a norepinephrine drip to a MAP goal under preceptor supervision.","how_sub_steps":[{"id":"aaaa0017-0000-4000-8000-000000000001","text":"Confirm the MAP goal and the titration parameters","sort_order":0,"completed":true},{"id":"aaaa0017-0000-4000-8000-000000000002","text":"Adjust in small increments and reassess before the next change","sort_order":1,"completed":true},{"id":"aaaa0017-0000-4000-8000-000000000003","text":"Watch the arterial line and the patient, not just the pump","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0017-0000-4000-8000-000000000001","text":"Chasing the MAP with big jumps overshot. Small increments with a pause to reassess held the goal steady.","timestamp":"2026-06-05T09:20:00Z","source":"note"},{"id":"bbbb0017-0000-4000-8000-000000000002","text":"Cross-checked the arterial line against a manual cuff before trusting the number to titrate.","timestamp":"2026-06-05T09:35:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0017-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-17a/640/480","type":"photo","caption":"Norepinephrine drip with titration parameters posted.","created_at":"2026-06-05T09:25:00Z"}],"media_links":[{"id":"dddd0017-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/vasopressor-titration.pdf","caption":"Vasopressor titration parameters and safety limits.","platform":"other","added_at":"2026-06-05T10:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Small titration steps with a deliberate reassessment pause held the MAP at goal without overshoot.","source":"in_app","captured_at":"2026-06-05T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"My first adjustment was too aggressive and overshot the MAP target.","source":"in_app","captured_at":"2026-06-05T18:30:00Z"}],"teaching_reflection":"I would teach a learner to titrate in small steps and reassess before the next change, and show me a trend where the MAP settled without swings.","composed_via":"in_app"}'::jsonb),

  ('d3710000-0000-4000-8000-000000000002',
   '{"what_will_you_do":"Implement the ventilator-associated pneumonia prevention bundle for an intubated patient.","how_sub_steps":[{"id":"aaaa0018-0000-4000-8000-000000000001","text":"Confirm head-of-bed elevation 30-45 degrees","sort_order":0,"completed":true},{"id":"aaaa0018-0000-4000-8000-000000000002","text":"Provide oral care with chlorhexidine on schedule","sort_order":1,"completed":true},{"id":"aaaa0018-0000-4000-8000-000000000003","text":"Coordinate the sedation pause and spontaneous breathing trial","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0018-0000-4000-8000-000000000001","text":"Bundling the sedation pause with the SBT and oral care meant fewer interruptions and a cleaner readiness check.","timestamp":"2026-06-08T07:50:00Z","source":"note"},{"id":"bbbb0018-0000-4000-8000-000000000002","text":"Head of bed had drifted to 20 degrees overnight. Small thing, big deal for VAP risk.","timestamp":"2026-06-08T08:10:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0018-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-18a/640/480","type":"photo","caption":"Head-of-bed angle indicator at 35 degrees.","created_at":"2026-06-08T07:55:00Z"},{"id":"cccc0018-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-18v/640/480","type":"video","caption":"Chlorhexidine oral care on the intubated patient.","created_at":"2026-06-08T08:05:00Z"}],"media_links":[{"id":"dddd0018-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/vap-prevention-bundle.pdf","caption":"Ventilator bundle elements and timing.","platform":"other","added_at":"2026-06-08T09:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Clustering the sedation pause, breathing trial, and oral care into one window reduced interruptions and made readiness clear.","source":"in_app","captured_at":"2026-06-08T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I did not check the head-of-bed angle early — it had drifted to 20 degrees overnight.","source":"in_app","captured_at":"2026-06-08T18:30:00Z"}],"teaching_reflection":"I would have a learner verify every bundle element by sight at the start of shift and show me the documented head-of-bed angle and oral-care times.","composed_via":"in_app"}'::jsonb),

  ('32a4240b-d3a1-4975-9752-f9a51822f8be',
   '{"what_will_you_do":"Care for a fresh post-op cardiac patient in the CVICU — hemodynamics, chest tubes, and pacing.","how_sub_steps":[{"id":"aaaa0019-0000-4000-8000-000000000001","text":"Trend hemodynamics and chest-tube output closely","sort_order":0,"completed":true},{"id":"aaaa0019-0000-4000-8000-000000000002","text":"Confirm pacer settings and capture","sort_order":1,"completed":true},{"id":"aaaa0019-0000-4000-8000-000000000003","text":"Watch for tamponade and bleeding red flags","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0019-0000-4000-8000-000000000001","text":"Chest-tube output jumped to 150 mL in an hour with a narrowing pulse pressure. Escalated for possible tamponade — early call was right.","timestamp":"2026-06-10T11:30:00Z","source":"note"},{"id":"bbbb0019-0000-4000-8000-000000000002","text":"I almost normalized the rising output as expected drainage. The pulse-pressure trend is what changed my mind.","timestamp":"2026-06-10T11:45:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0019-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-19a/640/480","type":"photo","caption":"Chest-tube collection chamber with hourly output marks.","created_at":"2026-06-10T11:35:00Z"},{"id":"cccc0019-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-19v/640/480","type":"video","caption":"Checking epicardial pacer settings and capture.","created_at":"2026-06-10T11:40:00Z"}],"media_links":[{"id":"dddd0019-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/post-op-cardiac-redflags.pdf","caption":"Post-op cardiac red-flag and tamponade reference.","platform":"other","added_at":"2026-06-10T12:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Trending chest-tube output against pulse pressure flagged possible tamponade early enough to escalate.","source":"in_app","captured_at":"2026-06-10T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"My first instinct was to normalize the rising drainage as expected rather than connect it to the narrowing pulse pressure.","source":"in_app","captured_at":"2026-06-10T18:30:00Z"}],"teaching_reflection":"I would teach a learner to read chest-tube output together with hemodynamic trends and show me the moment a trend, not a single number, drove the escalation.","composed_via":"in_app"}'::jsonb),

  ('d3710000-0000-4000-8000-000000000003',
   '{"what_will_you_do":"Interpret a series of arterial blood gases and tie the acid-base picture to the plan of care.","how_sub_steps":[{"id":"aaaa0020-0000-4000-8000-000000000001","text":"Read pH, then respiratory and metabolic components in order","sort_order":0,"completed":true},{"id":"aaaa0020-0000-4000-8000-000000000002","text":"Decide primary disorder and degree of compensation","sort_order":1,"completed":true},{"id":"aaaa0020-0000-4000-8000-000000000003","text":"Connect the gas to the next intervention","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0020-0000-4000-8000-000000000001","text":"Working pH then CO2 then bicarb in a fixed order kept me from jumping to the wrong primary disorder.","timestamp":"2026-06-12T10:10:00Z","source":"note"},{"id":"bbbb0020-0000-4000-8000-000000000002","text":"A mixed picture tripped me up until the preceptor had me check whether compensation was even appropriate.","timestamp":"2026-06-12T10:30:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0020-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-20a/640/480","type":"photo","caption":"ABG result with my stepwise interpretation noted in the margin.","created_at":"2026-06-12T10:15:00Z"}],"media_links":[{"id":"dddd0020-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/abg-interpretation-steps.pdf","caption":"Stepwise ABG interpretation worksheet.","platform":"other","added_at":"2026-06-12T11:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"A fixed read order — pH, CO2, then bicarb — kept me from naming the wrong primary disorder.","source":"in_app","captured_at":"2026-06-12T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"A mixed acid-base picture confused me until I checked whether the compensation was appropriate.","source":"in_app","captured_at":"2026-06-12T18:30:00Z"}],"teaching_reflection":"I would have a learner interpret ABGs in the same order every time and show me how the gas connected to the very next intervention.","composed_via":"in_app"}'::jsonb),

  ('d3710000-0000-4000-8000-000000000004',
   '{"what_will_you_do":"Participate in a rapid response for early clinical deterioration and contribute structured handoff.","how_sub_steps":[{"id":"aaaa0021-0000-4000-8000-000000000001","text":"Recognize the early-warning trigger and call early","sort_order":0,"completed":true},{"id":"aaaa0021-0000-4000-8000-000000000002","text":"Give a crisp SBAR to the responding team","sort_order":1,"completed":true},{"id":"aaaa0021-0000-4000-8000-000000000003","text":"Take a clear role and stay in it","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0021-0000-4000-8000-000000000001","text":"The early-warning score climbed before the patient looked sick. Calling on the trend instead of the gestalt bought time.","timestamp":"2026-06-16T14:20:00Z","source":"note"},{"id":"bbbb0021-0000-4000-8000-000000000002","text":"During the response I started to free-float between tasks. Taking one role made me more useful.","timestamp":"2026-06-16T14:40:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0021-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-21a/640/480","type":"photo","caption":"Early-warning score trend that triggered the call.","created_at":"2026-06-16T14:25:00Z"}],"media_links":[{"id":"dddd0021-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/rapid-response-roles.pdf","caption":"Rapid response team roles and SBAR script.","platform":"other","added_at":"2026-06-16T15:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Calling the rapid response on the rising early-warning trend, before the patient looked sick, bought the team time.","source":"in_app","captured_at":"2026-06-16T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I drifted between tasks during the response instead of owning one clear role.","source":"in_app","captured_at":"2026-06-16T18:30:00Z"}],"teaching_reflection":"I would teach a learner to trust early-warning trends and call early, and show me a response where they held one defined role start to finish.","composed_via":"in_app"}'::jsonb),

  ('d3710000-0000-4000-8000-000000000005',
   '{"what_will_you_do":"Assist with arterial line placement and manage hemodynamic monitoring afterward.","how_sub_steps":[{"id":"aaaa0022-0000-4000-8000-000000000001","text":"Level and zero the transducer at the phlebostatic axis","sort_order":0,"completed":true},{"id":"aaaa0022-0000-4000-8000-000000000002","text":"Run a square-wave test to check the waveform damping","sort_order":1,"completed":true},{"id":"aaaa0022-0000-4000-8000-000000000003","text":"Correlate the arterial number with a manual cuff","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0022-0000-4000-8000-000000000001","text":"The square-wave test showed overdamping — a small air bubble in the tubing. Cleared it and the waveform sharpened.","timestamp":"2026-06-18T09:50:00Z","source":"note"},{"id":"bbbb0022-0000-4000-8000-000000000002","text":"Re-leveling after the bed was raised changed the reading by 8 mmHg. Easy to forget, real consequence.","timestamp":"2026-06-18T10:10:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0022-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-22a/640/480","type":"photo","caption":"Transducer leveled at the phlebostatic axis.","created_at":"2026-06-18T09:55:00Z"},{"id":"cccc0022-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-22v/640/480","type":"video","caption":"Square-wave test showing the waveform before and after clearing the bubble.","created_at":"2026-06-18T10:00:00Z"}],"media_links":[{"id":"dddd0022-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/arterial-line-monitoring.pdf","caption":"Arterial line leveling, zeroing, and waveform reference.","platform":"other","added_at":"2026-06-18T11:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Running a square-wave test caught overdamping from an air bubble and sharpened the waveform.","source":"in_app","captured_at":"2026-06-18T18:30:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I forgot to re-level after the bed was raised, which shifted the reading by 8 mmHg.","source":"in_app","captured_at":"2026-06-18T18:30:00Z"}],"teaching_reflection":"I would teach a learner to re-level and re-zero after any position change and show me a square-wave test confirming an optimally damped waveform.","composed_via":"in_app"}'::jsonb)
) AS v(id, plan_patch, act_patch, review_patch)
WHERE ts.id = v.id::uuid;

-- ---------------------------------------------------------------------------
-- Section 2 — Pediatrics Rotation (May): plan + act + review patches
-- ---------------------------------------------------------------------------
UPDATE timeline_steps ts SET metadata =
  ts.metadata
  || jsonb_build_object('plan',   COALESCE(ts.metadata->'plan',   '{}'::jsonb) || v.plan_patch)
  || jsonb_build_object('act',    COALESCE(ts.metadata->'act',    '{}'::jsonb) || v.act_patch)
  || jsonb_build_object('review', COALESCE(ts.metadata->'review', '{}'::jsonb) || v.review_patch)
FROM (VALUES
  ('67363a44-e5ef-4051-b42b-038b6ae847ed',
   '{"what_will_you_do":"Run a well-child and sick-visit clinic session at Harriet Lane, including growth plotting and family teaching.","how_sub_steps":[{"id":"aaaa0011-0000-4000-8000-000000000001","text":"Plot weight, length, and head circumference on the growth chart","sort_order":0,"completed":true},{"id":"aaaa0011-0000-4000-8000-000000000002","text":"Get down to the child''s eye level before the exam","sort_order":1,"completed":true},{"id":"aaaa0011-0000-4000-8000-000000000003","text":"Teach the caregiver one concrete next step before they leave","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0011-0000-4000-8000-000000000001","text":"A toddler crossing two percentile lines down caught my eye on the chart — the visit refocused on feeding history.","timestamp":"2026-05-06T10:20:00Z","source":"note"},{"id":"bbbb0011-0000-4000-8000-000000000002","text":"Letting the child hold the stethoscope first turned a screaming exam into a calm one.","timestamp":"2026-05-06T11:05:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0011-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-11a/640/480","type":"photo","caption":"Growth chart showing the downward percentile crossing.","created_at":"2026-05-06T10:25:00Z"}],"media_links":[{"id":"dddd0011-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/pediatric-growth-charts.pdf","caption":"WHO/CDC pediatric growth chart interpretation guide.","platform":"other","added_at":"2026-05-06T12:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Plotting growth carefully surfaced a two-line percentile drop that reframed the whole visit around feeding.","source":"in_app","captured_at":"2026-05-06T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I started the exam standing over the toddler and lost their trust before I built it back.","source":"in_app","captured_at":"2026-05-06T17:00:00Z"}],"teaching_reflection":"I would teach a learner to get to the child''s level and let them touch the equipment first, and show me a growth chart they have plotted and interpreted.","composed_via":"in_app"}'::jsonb),

  ('2b8f39df-4133-4b92-8f29-011a49f7ce60',
   '{"what_will_you_do":"Complete a head-to-toe assessment on a school-age child using developmentally appropriate technique.","how_sub_steps":[{"id":"aaaa0012-0000-4000-8000-000000000001","text":"Save the invasive or scary parts for last","sort_order":0,"completed":true},{"id":"aaaa0012-0000-4000-8000-000000000002","text":"Use distraction and choices to keep the child engaged","sort_order":1,"completed":true},{"id":"aaaa0012-0000-4000-8000-000000000003","text":"Compare findings to age-expected norms","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0012-0000-4000-8000-000000000001","text":"Offering a choice — left ear or right ear first — gave the child control and the exam went smoothly.","timestamp":"2026-05-09T10:00:00Z","source":"note"},{"id":"bbbb0012-0000-4000-8000-000000000002","text":"I checked the throat too early and lost cooperation for the heart and lungs. Order matters with kids.","timestamp":"2026-05-09T10:20:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0012-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-12a/640/480","type":"photo","caption":"Pediatric assessment sequence card for school-age children.","created_at":"2026-05-09T10:05:00Z"},{"id":"cccc0012-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-12v/640/480","type":"video","caption":"Using choices and distraction during an ear exam.","created_at":"2026-05-09T10:10:00Z"}],"media_links":[{"id":"dddd0012-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/pediatric-assessment-sequence.pdf","caption":"Developmentally ordered pediatric assessment sequence.","platform":"other","added_at":"2026-05-09T11:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Giving the child small choices kept them cooperative through the whole exam.","source":"in_app","captured_at":"2026-05-09T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I examined the throat too early and lost cooperation for the heart and lung exam.","source":"in_app","captured_at":"2026-05-09T17:00:00Z"}],"teaching_reflection":"I would teach a learner to sequence pediatric exams least-invasive first and show me an assessment where the throat and ears came last.","composed_via":"in_app"}'::jsonb),

  ('99026535-c5b8-45d7-ab8b-70d1427e830b',
   '{"what_will_you_do":"Provide Foley catheter care for a pediatric patient with strict sterile and comfort attention.","how_sub_steps":[{"id":"aaaa0013-0000-4000-8000-000000000001","text":"Explain each step to the child and caregiver first","sort_order":0,"completed":true},{"id":"aaaa0013-0000-4000-8000-000000000002","text":"Maintain a sterile field and secure the catheter to prevent traction","sort_order":1,"completed":true},{"id":"aaaa0013-0000-4000-8000-000000000003","text":"Assess output color, clarity, and volume","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0013-0000-4000-8000-000000000001","text":"Securing the catheter to the thigh with slack prevented traction when the child moved — comfort and infection prevention in one step.","timestamp":"2026-05-14T11:10:00Z","source":"note"},{"id":"bbbb0013-0000-4000-8000-000000000002","text":"I narrated the sterile steps for the parent and it visibly lowered everyone''s anxiety.","timestamp":"2026-05-14T11:25:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0013-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-13a/640/480","type":"photo","caption":"Catheter secured to the thigh with appropriate slack.","created_at":"2026-05-14T11:15:00Z"}],"media_links":[{"id":"dddd0013-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/cauti-prevention-bundle.pdf","caption":"Pediatric CAUTI-prevention care bundle.","platform":"other","added_at":"2026-05-14T12:00:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Securing the catheter with slack protected against traction and doubled as comfort care.","source":"in_app","captured_at":"2026-05-14T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I broke my sterile field momentarily reaching for supplies I should have set up within arm''s reach first.","source":"in_app","captured_at":"2026-05-14T17:00:00Z"}],"teaching_reflection":"I would have a learner stage every sterile supply before they start and show me a secured catheter plus a charted output assessment.","composed_via":"in_app"}'::jsonb),

  ('cb8ffb75-0b91-48bf-b72f-f7b7a1d519f0',
   '{"what_will_you_do":"Run a community visit at the Wald center — home-style assessment, social history, and resource teaching.","how_sub_steps":[{"id":"aaaa0014-0000-4000-8000-000000000001","text":"Assess the home and social context, not just the patient","sort_order":0,"completed":true},{"id":"aaaa0014-0000-4000-8000-000000000002","text":"Screen for food, housing, and transportation barriers","sort_order":1,"completed":true},{"id":"aaaa0014-0000-4000-8000-000000000003","text":"Connect the family to one concrete community resource","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0014-0000-4000-8000-000000000001","text":"The medication non-adherence was really a transportation problem — they could not get to the pharmacy. Set up mail-order delivery.","timestamp":"2026-05-20T13:30:00Z","source":"note"},{"id":"bbbb0014-0000-4000-8000-000000000002","text":"Asking one open question about a typical day told me more than the whole intake form.","timestamp":"2026-05-20T13:50:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0014-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-14a/640/480","type":"photo","caption":"Community resource referral list for the family.","created_at":"2026-05-20T14:00:00Z"}],"media_links":[{"id":"dddd0014-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/social-determinants-screen.pdf","caption":"Social determinants of health screening tool.","platform":"other","added_at":"2026-05-20T14:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"One open question about a typical day uncovered a transportation barrier that explained the missed medications.","source":"in_app","captured_at":"2026-05-20T18:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I almost charted non-adherence as a knowledge gap before I understood the real barrier.","source":"in_app","captured_at":"2026-05-20T18:00:00Z"}],"teaching_reflection":"I would teach a learner to screen for social barriers before judging adherence, and show me one concrete resource they connected a family to.","composed_via":"in_app"}'::jsonb),

  ('af9bd331-81b5-4213-84ea-468bae2a9962',
   '{"what_will_you_do":"Place and verify a pediatric NG feeding tube and confirm placement before use.","how_sub_steps":[{"id":"aaaa0015-0000-4000-8000-000000000001","text":"Measure NEX and mark the tube before insertion","sort_order":0,"completed":true},{"id":"aaaa0015-0000-4000-8000-000000000002","text":"Insert gently and pause if the child gags or color changes","sort_order":1,"completed":true},{"id":"aaaa0015-0000-4000-8000-000000000003","text":"Confirm placement per policy before any feeding","sort_order":2,"completed":true}]}'::jsonb,
   '{"observations":[{"id":"bbbb0015-0000-4000-8000-000000000001","text":"Measuring nose-ear-xiphoid first meant I taped at the right depth on the first try.","timestamp":"2026-05-23T10:40:00Z","source":"note"},{"id":"bbbb0015-0000-4000-8000-000000000002","text":"I wanted to trust the auscultation whoosh, but policy is pH and x-ray for kids. Waited for confirmation before feeding.","timestamp":"2026-05-23T11:00:00Z","source":"voice"}],"media_uploads":[{"id":"cccc0015-0000-4000-8000-000000000001","uri":"https://picsum.photos/seed/emily-15a/640/480","type":"photo","caption":"NEX measurement marked on the NG tube before insertion.","created_at":"2026-05-23T10:35:00Z"},{"id":"cccc0015-0000-4000-8000-000000000002","uri":"https://picsum.photos/seed/emily-15v/640/480","type":"video","caption":"Gentle insertion technique with pause points.","created_at":"2026-05-23T10:45:00Z"}],"media_links":[{"id":"dddd0015-0000-4000-8000-000000000001","url":"https://jhu-demo.edu/clinical/ng-placement-verification.pdf","caption":"Pediatric NG placement verification policy.","platform":"other","added_at":"2026-05-23T11:30:00Z"}]}'::jsonb,
   '{"sections":[{"prompt":"what_worked","prompt_label":"What worked?","content":"Measuring NEX and marking the tube first got me the right insertion depth on the first attempt.","source":"in_app","captured_at":"2026-05-23T17:00:00Z"},{"prompt":"what_didnt","prompt_label":"What didn''t?","content":"I was tempted to verify by auscultation alone — the unreliable method — instead of waiting for pH and x-ray.","source":"in_app","captured_at":"2026-05-23T17:00:00Z"}],"teaching_reflection":"I would teach a learner that the auscultation whoosh does not confirm placement, and have them show me the pH or radiographic confirmation before any feed.","composed_via":"in_app"}'::jsonb)
) AS v(id, plan_patch, act_patch, review_patch)
WHERE ts.id = v.id::uuid;

-- ---------------------------------------------------------------------------
-- Section 4 — Critical Care future steps (planned, not yet happened): plan only
-- These are dated after today (2026-06-20); seeding captures or reflections on
-- work that has not occurred would be unrealistic, so they get the WHAT/HOW
-- summary and a planned shift agenda (beats) only.
-- ---------------------------------------------------------------------------
UPDATE timeline_steps ts SET metadata =
  ts.metadata
  || jsonb_build_object('plan', COALESCE(ts.metadata->'plan', '{}'::jsonb) || v.plan_patch)
FROM (VALUES
  ('d3710000-0000-4000-8000-000000000006',
   '{"what_will_you_do":"Give a structured CVICU handoff for a complex post-op patient, leading with hemodynamic priorities.","how_sub_steps":[{"id":"aaaa0023-0000-4000-8000-000000000001","text":"Pre-build an SBAR with drips, lines, and pacer settings","sort_order":0,"completed":false},{"id":"aaaa0023-0000-4000-8000-000000000002","text":"Lead with the one thing that could change in the next hour","sort_order":1,"completed":false},{"id":"aaaa0023-0000-4000-8000-000000000003","text":"Close with a read-back of pending tasks","sort_order":2,"completed":false}]}'::jsonb),
  ('d3710000-0000-4000-8000-000000000007',
   '{"what_will_you_do":"Run an ACLS code blue simulation and own a defined resuscitation role.","how_sub_steps":[{"id":"aaaa0024-0000-4000-8000-000000000001","text":"Review the ACLS algorithm and role assignments beforehand","sort_order":0,"completed":false},{"id":"aaaa0024-0000-4000-8000-000000000002","text":"Practice closed-loop communication for every order","sort_order":1,"completed":false},{"id":"aaaa0024-0000-4000-8000-000000000003","text":"Debrief against the algorithm timing","sort_order":2,"completed":false}]}'::jsonb),
  ('d3710000-0000-4000-8000-000000000008',
   '{"what_will_you_do":"Manage sedation and analgesia for a ventilated patient using RASS-guided titration.","how_sub_steps":[{"id":"aaaa0025-0000-4000-8000-000000000001","text":"Set the target RASS with the team","sort_order":0,"completed":false},{"id":"aaaa0025-0000-4000-8000-000000000002","text":"Titrate to target and reassess on a schedule","sort_order":1,"completed":false},{"id":"aaaa0025-0000-4000-8000-000000000003","text":"Coordinate the daily sedation interruption","sort_order":2,"completed":false}]}'::jsonb)
) AS v(id, plan_patch)
WHERE ts.id = v.id::uuid;

